  uint8_t r = baseColor[0] * factor;
  uint8_t g = baseColor[1] * factor;
  uint8_t b = baseColor[2] * factor;

  // Apply to all LEDs
  for (int i = 0; i < NUM_LEDS; i++) {
    ring.setPixelColor(i, ring.Color(r, g, b));
  }
  ring.show();
}

